esqlQuery.esql:
FROM metrics-influxdb.otel-*
// Storage writer timeout counter (cumulative)
| WHERE COALESCE(metrics.storage_writer_timeouts, storage_writer_timeouts) IS NOT NULL
// Detect increase in timeouts over the window
| STATS min_timeout = MIN(COALESCE(metrics.storage_writer_timeouts, storage_writer_timeouts)),
    max_timeout = MAX(COALESCE(metrics.storage_writer_timeouts, storage_writer_timeouts))
  BY host.name
| EVAL timeout_increase = max_timeout - min_timeout
// Alert when any new writer timeouts occurred
| WHERE timeout_increase > 0
